{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Extract and validate the command type and order data from the input JSON.",
      "behavior": "Parse the input JSON to extract 'command' and 'order_data' fields, validate that command is one of 'place', 'cancel', 'track'.",
      "boundary": {
        "in_scope": ["Parsing JSON", "Validating command type"],
        "out_of_scope": ["Executing any order operation", "Accessing data stores"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "JSON with command and order_data", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "command", "description": "Validated command string (place/cancel/track)", "consumer": "parent"},
        {"name": "order_data", "description": "Parsed order data object", "consumer": "parent"}
      ],
      "preconditions": ["Input is valid JSON"],
      "postconditions": ["Command is one of place/cancel/track", "order_data is extracted"],
      "guarantees": ["Returns error if command invalid"],
      "composition_role": "transform",
      "stop_decompose": true,
      "stop_reason": "Pure parsing and validation function"
    },
    {
      "name": "PlaceOrder",
      "purpose": "Create a new order, update inventory, and process payment.",
      "behavior": "Generate order ID, store order in orders with status 'placed', decrement inventory, process payment via payments store.",
      "boundary": {
        "in_scope": ["Creating order record", "Updating inventory", "Processing payment"],
        "out_of_scope": ["Canceling orders", "Tracking orders"]
      },
      "semantic_inputs": [
        {"name": "order_data", "description": "Order details including items and payment info", "source": "ParseCommand output"}
      ],
      "semantic_outputs": [
        {"name": "order_id", "description": "Generated unique order ID", "consumer": "parent"},
        {"name": "status", "description": "Order status after placement", "consumer": "parent"},
        {"name": "message", "description": "Success or error message", "consumer": "parent"}
      ],
      "preconditions": ["Inventory has sufficient stock", "Payment method valid"],
      "postconditions": ["Order created with status 'placed'", "Inventory decremented", "Payment processed"],
      "guarantees": ["Atomic operation: all or nothing"],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "Can be further decomposed into inventory check, payment, order creation"
    },
    {
      "name": "CancelOrder",
      "purpose": "Cancel an existing order if not shipped, restore inventory, and refund payment.",
      "behavior": "Look up order by order_id, check status is not 'shipped', update status to 'cancelled', restore inventory, process refund.",
      "boundary": {
        "in_scope": ["Checking order status", "Updating order status", "Restoring inventory", "Processing refund"],
        "out_of_scope": ["Placing orders", "Tracking orders"]
      },
      "semantic_inputs": [
        {"name": "order_data", "description": "Contains order_id to cancel", "source": "ParseCommand output"}
      ],
      "semantic_outputs": [
        {"name": "order_id", "description": "ID of cancelled order", "consumer": "parent"},
        {"name": "status", "description": "New status after cancellation", "consumer": "parent"},
        {"name": "message", "description": "Success or error message", "consumer": "parent"}
      ],
      "preconditions": ["Order exists", "Order status is not 'shipped'"],
      "postconditions": ["Order status changed to 'cancelled'", "Inventory restored", "Payment refunded"],
      "guarantees": ["Cannot cancel shipped orders", "Atomic operation"],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "Can be further decomposed into status check, inventory restore, refund"
    },
    {
      "name": "TrackOrder",
      "purpose": "Retrieve and return the current status and details of an order.",
      "behavior": "Look up order by order_id from orders store, return status and relevant details.",
      "boundary": {
        "in_scope": ["Reading order status", "Returning order details"],
        "out_of_scope": ["Modifying orders", "Accessing inventory or payments"]
      },
      "semantic_inputs": [
        {"name": "order_data", "description": "Contains order_id to track", "source": "ParseCommand output"}
      ],
      "semantic_outputs": [
        {"name": "order_id", "description": "ID of tracked order", "consumer": "parent"},
        {"name": "status", "description": "Current order status", "consumer": "parent"},
        {"name": "message", "description": "Order details or error", "consumer": "parent"}
      ],
      "preconditions": ["Order exists"],
      "postconditions": ["Order status returned"],
      "guarantees": ["Read-only operation"],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "Simple read operation"
    }
  ],
  "decomposition_rationale": "The parent OrderSystem is decomposed into four children: ParseCommand to handle input validation and routing, and three command-specific functions (PlaceOrder, CancelOrder, TrackOrder) that each handle their respective business logic. This separation ensures each child has a single responsibility and no sibling calls.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {"from": "parent", "to": "ParseCommand", "data": "input JSON", "note": "Parse and validate command"},
    {"from": "ParseCommand", "to": "parent", "data": "command and order_data", "note": "Return parsed data"},
    {"from": "parent", "to": "PlaceOrder", "data": "order_data", "note": "If command is 'place'"},
    {"from": "parent", "to": "CancelOrder", "data": "order_data", "note": "If command is 'cancel'"},
    {"from": "parent", "to": "TrackOrder", "data": "order_data", "note": "If command is 'track'"},
    {"from": "PlaceOrder", "to": "parent", "data": "order_id, status, message", "note": "Return result"},
    {"from": "CancelOrder", "to": "parent", "data": "order_id, status, message", "note": "Return result"},
    {"from": "TrackOrder", "to": "parent", "data": "order_id, status, message", "note": "Return result"}
  ]
}

